import json
import pandas as pd

# Load data
with open(locals()['var_function-call-7958927153082786885'], 'r') as f:
    case_data = json.load(f)
with open(locals()['var_function-call-7047842063131975210'], 'r') as f:
    hist_data = json.load(f)

def clean_id(val):
    if not val or val == 'None': return None
    if isinstance(val, str):
        val = val.strip()
        if val.startswith('#'):
            return val[1:]
    return val

def parse_date(date_str):
    if not date_str or date_str == 'None': return None
    try:
        return pd.to_datetime(date_str)
    except:
        return None

start_date = pd.Timestamp('2022-04-10', tz='UTC')
end_date = pd.Timestamp('2023-04-10', tz='UTC')

# Track cases handled per agent
agent_handled_cases = {} # Agent -> Set(CaseID)

# From Case
for r in case_data:
    created = parse_date(r.get('createddate'))
    closed = parse_date(r.get('closeddate'))
    owner = clean_id(r.get('ownerid'))
    case_id = clean_id(r.get('id'))

    if not owner or not case_id: continue

    # Active in window
    if created and created <= end_date:
        if closed is None or closed >= start_date:
            if owner not in agent_handled_cases: agent_handled_cases[owner] = set()
            agent_handled_cases[owner].add(case_id)

# From History
hist_in_window = []
for r in hist_data:
    d = parse_date(r.get('createddate'))
    if d and d >= start_date and d <= end_date:
        hist_in_window.append(r)

        old = clean_id(r.get('oldvalue__c'))
        new = clean_id(r.get('newvalue__c'))
        case_id = clean_id(r.get('caseid__c'))

        if new:
            if new not in agent_handled_cases: agent_handled_cases[new] = set()
            agent_handled_cases[new].add(case_id)
        if old:
            if old not in agent_handled_cases: agent_handled_cases[old] = set()
            agent_handled_cases[old].add(case_id)

# Candidates: Agents who handled > 0 cases
candidates = [a for a, cases in agent_handled_cases.items() if len(cases) > 0]

# Calculate Transfer Counts
agent_transfer_counts = {agent: 0 for agent in candidates}

for r in hist_in_window:
    old = clean_id(r.get('oldvalue__c'))
    if old and old in agent_transfer_counts:
        agent_transfer_counts[old] += 1

if not agent_transfer_counts:
    result = "None"
else:
    min_count = min(agent_transfer_counts.values())
    min_agents = [a for a, c in agent_transfer_counts.items() if c == min_count]

    # Tie breaker: Max handled cases?
    # Get handled counts for min_agents
    min_agents_handled = [(a, len(agent_handled_cases[a])) for a in min_agents]
    # Sort by handled desc, then ID asc
    min_agents_handled.sort(key=lambda x: (-x[1], x[0]))

    result = min_agents_handled[0][0]

    # Debug info
    debug = {
        "min_count": min_count,
        "winner": result,
        "winner_handled": min_agents_handled[0][1],
        "runner_up": min_agents_handled[1] if len(min_agents_handled) > 1 else None
    }

print("__RESULT__:")
print(json.dumps(debug))

